    """Test that delete_secret properly validates RecoveryWindowInDays"""
    client = boto3.client("secretsmanager", region_name="us-east-1")

    test_cases = [
        # (RecoveryWindowInDays, ForceDeleteWithoutRecovery, should_fail, description)
        (0, True, True, "RecoveryWindowInDays=0 with ForceDeleteWithoutRecovery"),
        (0, False, True, "RecoveryWindowInDays=0 without ForceDeleteWithoutRecovery"),
