        (30, False, False, "RecoveryWindowInDays=30 (valid maximum)"),
        (15, False, False, "RecoveryWindowInDays=15 (valid middle value)"),
        (None, True, False, "No RecoveryWindowInDays with ForceDeleteWithoutRecovery"),
        (None, False, False, "No RecoveryWindowInDays without ForceDeleteWithoutRecovery"),
    ]

    for recovery_window, force_delete, should_fail, description in test_cases:
        # Create a fresh secret for each test
        client.create_secret(Name=f"test-secret-{description}", SecretString="password")

        try:
            kwargs = {"SecretId": f"test-secret-{description}"}
            if recovery_window is not None:
                kwargs["RecoveryWindowInDays"] = recovery_window
            if force_delete:
                kwargs["ForceDeleteWithoutRecovery"] = True

            client.delete_secret(**kwargs)
            if should_fail:
                print(f"FAIL: {description} - Should have raised an exception")
            else:
                print(f"PASS: {description} - Correctly allowed")
        except Exception as e:
            if should_fail:
                print(f"PASS: {description} - Correctly rejected: {str(e)[:100]}")
